async function sendResetEmail(env, toEmail, resetUrl, parentName){
  const apiKey = env.RESEND_API_KEY;
  if(!apiKey) throw new Error('Email service not configured');
  const html = `
    <div style="font-family: Inter, Arial, sans-serif; max-width: 560px; margin: 0 auto; padding: 24px; background: #f7f7f7;">
      <div style="background: #fff; border-radius: 12px; padding: 32px; border: 1px solid #eee;">
        <div style="margin-bottom: 20px;">
          <span style="display:inline-block; background:#010101; color:#fff; padding:6px 12px; border-radius:6px; font-weight:700; letter-spacing:.04em; font-size:.85rem;">TI BASEBALL</span>
        </div>
        <h2 style="margin: 0 0 12px; font-family: Anton, Arial, sans-serif; letter-spacing: .02em;">Reset Your Password</h2>
        <p style="color: #333; line-height: 1.55;">Hi ${parentName ? parentName.split(' ')[0] : 'there'},</p>
        <p style="color: #333; line-height: 1.55;">We received a request to reset the password on your TI Baseball account. Click the button below to set a new one. This link expires in <strong>1 hour</strong>.</p>
        <p style="margin: 28px 0;">
          <a href="${resetUrl}" style="display:inline-block; background:#EC2C8A; color:#fff; text-decoration:none; padding:13px 26px; border-radius:8px; font-family:Anton,Arial,sans-serif; letter-spacing:.04em; font-size:1rem;">Set New Password</a>
        </p>
        <p style="color: #666; font-size: .85rem; line-height: 1.55;">If the button doesn't work, paste this link into your browser:<br><a href="${resetUrl}" style="color:#1FBFC4; word-break:break-all;">${resetUrl}</a></p>
        <p style="color: #888; font-size: .85rem; margin-top: 28px;">Didn't request this? You can safely ignore this email — your password won't change unless you click the link above.</p>
        <hr style="border:none; border-top:1px solid #eee; margin: 24px 0;">
        <p style="color: #888; font-size: .8rem;">TI Baseball &middot; Ajax, Ontario &middot; tibaseball.com</p>
      </div>
    </div>
  `;
  const r = await fetch('https://api.resend.com/emails', {
    method:'POST',
    headers:{ 'Authorization': `Bearer ${apiKey}`, 'Content-Type':'application/json' },
    body: JSON.stringify({
      from: 'TI Baseball <noreply@tibaseball.com>',
      to: [toEmail],
      subject: 'Reset your TI Baseball password',
      html
    })
  });
  if(!r.ok){
    const txt = await r.text();
    throw new Error(`Resend ${r.status}: ${txt.slice(0,200)}`);
  }
  return true;
}

async function handleForgotPassword(request, env){
  if(request.method !== 'POST') return new Response('Method not allowed',{status:405});
  let body;
  try { body = await request.json(); } catch { return jsonResponse({error:'Invalid JSON'},400); }
  const email = normalizeEmail(body.email);
  if(!email || !isValidEmail(email)){
    return jsonResponse({ ok:true });
  }
  const user = await env.USERS_KV.get(email, 'json');
  if(user){
    const token = newToken(24);
    const record = { email, createdAt: Date.now() };
    await env.RESET_KV.put(token, JSON.stringify(record), { expirationTtl: 60*60 });
    const url = new URL(request.url);
    const resetUrl = `${url.protocol}//${url.host}/reset-password?token=${token}`;
    try {
      await sendResetEmail(env, email, resetUrl, user.parentName);
    } catch(e){
      console.log('reset email failed:', String(e.message||e));
    }
  }
  return jsonResponse({ ok:true });
}

async function handleResetPassword(request, env){
  if(request.method !== 'POST') return new Response('Method not allowed',{status:405});
  let body;
  try { body = await request.json(); } catch { return jsonResponse({error:'Invalid JSON'},400); }
  const token = (body.token||'').trim();
  const password = body.password || '';
  if(!token) return jsonResponse({error:'Missing reset token'},400);
  if(!password || password.length < 8) return jsonResponse({error:'Password must be at least 8 characters'},400);
  const raw = await env.RESET_KV.get(token);
  if(!raw) return jsonResponse({error:'Reset link is invalid or expired. Please request a new one.'},400);
  let record;
  try { record = JSON.parse(raw); } catch { return jsonResponse({error:'Reset link malformed'},400); }
  const user = await env.USERS_KV.get(record.email, 'json');
  if(!user) return jsonResponse({error:'Account not found'},404);
  user.passwordHash = await hashPassword(password);
  await env.USERS_KV.put(record.email, JSON.stringify(user));
  await env.RESET_KV.delete(token);
  const sessTok = await startSession(env, record.email);
  return jsonResponse(
    { ok:true, email: record.email },
    200,
    { 'Set-Cookie': sessionCookie(sessTok, 60*60*24*30) }
  );
}

// ==== admin_handlers.js ====
// ============================================================
// ADMIN MODULE  —  Coach-facing administration
// ============================================================
const ADMIN_EMAILS = ['crosbyathletics321@gmail.com','christopherscotthastings@gmail.com'];

function isAdminEmail(email){ return ADMIN_EMAILS.includes((email||'').toLowerCase()); }

async function requireAdmin(request, env){
  const auth = await requireAuth(request, env);
  if(!auth) return { error: jsonResponse({error:'Not signed in'},401) };
  if(!isAdminEmail(auth.user.email)) return { error: jsonResponse({error:'Forbidden'},403) };
  return { auth };
}

function creditSummary(user){
  const now = Date.now();
  let available = 0, used = 0, expired = 0;
  let nextExpiry = null;
  const lots = (user.credits||[]).map(lot => {
    const remaining = (lot.count||0) - (lot.used||0);
    const isExpired = lot.expiresAt <= now;
    const isAvailable = remaining > 0 && !isExpired;
    if(isAvailable){
      available += remaining;
      if(!nextExpiry || lot.expiresAt < nextExpiry) nextExpiry = lot.expiresAt;
    } else if(isExpired){
      expired += remaining > 0 ? remaining : 0;
    }
    used += (lot.used||0);
    return {
      id: lot.id, count: lot.count, used: lot.used||0, remaining,
      purchasedAt: lot.purchasedAt, expiresAt: lot.expiresAt,
      source: lot.source, isExpired, isAvailable
    };
  });
  return { available, used, expired, nextExpiry, lots };
}

async function handleAdminUsers(request, env){
  const a = await requireAdmin(request, env);
  if(a.error) return a.error;
  // List all users
  const out = [];
  let cursor = undefined;
  do {
    const page = await env.USERS_KV.list({ cursor, limit: 1000 });
    for(const k of page.keys){
      const u = await env.USERS_KV.get(k.name, 'json');
      if(!u) continue;
      const sum = creditSummary(u);
      // Derive program tags from history
      const tags = new Set();
      const groupMap = {
        'one-on-one':'1-on-1',
        'monday-drop-in':'Monday Night',
        'monday-monthly':'Monday Night',
        'monday-monthly_renewal':'Monday Night',
        'camps-morning':'Camps',
        'camps-afternoon':'Camps',
        'academy-full':'Academy',
        'academy-monthly':'Academy',
        'academy':'Academy'
      };
      for(const b of (u.bookings||[])){
        const sv = (b.source||'').toString();
        if(groupMap[sv]) tags.add(groupMap[sv]);
        for(const k of Object.keys(groupMap)){ if(sv.startsWith(k)) tags.add(groupMap[k]); }
      }
      for(const p of (u.preorders||[])){ if(groupMap[p.program]) tags.add(groupMap[p.program]); }
      if(u.subscription && u.subscription.program && groupMap[u.subscription.program]) tags.add(groupMap[u.subscription.program]);
      const _now = Date.now();
      for(const lot of (u.credits||[])){
        const rem = (lot.count||0) - (lot.used||0);
        if(rem <= 0 || lot.expiresAt <= _now) continue;
        const prog = lot.program || '1-on-1';
        if(prog === 'academy') tags.add('Academy');
        else if(prog === '1-on-1') tags.add('1-on-1');
        if(groupMap[lot.source]) tags.add(groupMap[lot.source]);
      }
      if((u.campRegistrations||[]).length > 0) tags.add('Camps');
      out.push({
        email: u.email,
        parentName: u.parentName,
        athleteName: u.athleteName,
        phone: u.phone,
        level: u.level,
        athleteDob: u.athleteDob,
        createdAt: u.createdAt,
        creditsAvailable: sum.available,
        creditsUsed: sum.used,
        nextExpiry: sum.nextExpiry,
        subscriptionActive: !!(u.subscription && u.subscription.active),
        bookingsCount: (u.bookings||[]).length,
        preordersCount: (u.preorders||[]).length,
        programs: Array.from(tags).sort(),
        isAdmin: isAdminEmail(u.email)
      });
    }
    cursor = page.list_complete ? undefined : page.cursor;
  } while(cursor);
  out.sort((x,y) => (y.createdAt||0) - (x.createdAt||0));
  return jsonResponse({ users: out });
}

async function handleAdminUserDetail(request, env, email){
  const a = await requireAdmin(request, env);
  if(a.error) return a.error;
  const user = await env.USERS_KV.get(email, 'json');
  if(!user) return jsonResponse({error:'User not found'},404);
  const sum = creditSummary(user);
  // strip passwordHash for safety
  const { passwordHash, ...safe } = user;
  return jsonResponse({ user: safe, summary: sum });
}

async function handleAdminUserUpdate(request, env, email){
  const a = await requireAdmin(request, env);
  if(a.error) return a.error;
  if(request.method !== 'PATCH' && request.method !== 'PUT') return new Response('Method not allowed',{status:405});
  const user = await env.USERS_KV.get(email, 'json');
  if(!user) return jsonResponse({error:'User not found'},404);
  let body;
  try { body = await request.json(); } catch { return jsonResponse({error:'Invalid JSON'},400); }
  const fields = ['parentName','athleteName','athleteDob','level','phone'];
  for(const f of fields){
    if(body[f] !== undefined) user[f] = String(body[f]||'').trim();
  }
  await env.USERS_KV.put(email, JSON.stringify(user));
  return jsonResponse({ ok:true });
}

async function handleAdminAddCredits(request, env, email){
  const a = await requireAdmin(request, env);
  if(a.error) return a.error;
  if(request.method !== 'POST') return new Response('Method not allowed',{status:405});
  const user = await env.USERS_KV.get(email, 'json');
  if(!user) return jsonResponse({error:'User not found'},404);
  let body;
  try { body = await request.json(); } catch { return jsonResponse({error:'Invalid JSON'},400); }
  const count = parseInt(body.count, 10);
  const days = parseInt(body.expiresInDays || 30, 10);
  const reason = (body.reason||'admin_grant').slice(0,80);
  if(!(count > 0 && count <= 50)) return jsonResponse({error:'Count must be 1-50'},400);
  if(!(days > 0 && days <= 365)) return jsonResponse({error:'Days must be 1-365'},400);
  const now = Date.now();
  const lot = {
    id: newToken(8),
    count, used:0,
    purchasedAt: now,
    expiresAt: now + days*24*60*60*1000,
    source: reason
  };
  user.credits = (user.credits||[]).concat([lot]);
  await env.USERS_KV.put(email, JSON.stringify(user));
  return jsonResponse({ ok:true, lot });
}

async function handleAdminLotAction(request, env, email, lotId){
  const a = await requireAdmin(request, env);
  if(a.error) return a.error;
  const user = await env.USERS_KV.get(email, 'json');
  if(!user) return jsonResponse({error:'User not found'},404);
  const lots = user.credits || [];
  const idx = lots.findIndex(l => l.id === lotId);
  if(idx < 0) return jsonResponse({error:'Lot not found'},404);

  if(request.method === 'DELETE'){
    lots.splice(idx, 1);
    user.credits = lots;
    await env.USERS_KV.put(email, JSON.stringify(user));
    return jsonResponse({ ok:true, deleted:true });
  }
  if(request.method === 'PATCH'){
    let body;
    try { body = await request.json(); } catch { return jsonResponse({error:'Invalid JSON'},400); }
    if(body.extendDays !== undefined){
      const ed = parseInt(body.extendDays,10);
      if(!(Number.isFinite(ed) && ed >= -365 && ed <= 365)) return jsonResponse({error:'extendDays must be -365..365'},400);
      lots[idx].expiresAt = (lots[idx].expiresAt||Date.now()) + ed*24*60*60*1000;
    }
    if(body.setCount !== undefined){
      const nc = parseInt(body.setCount,10);
      if(!(nc >= 0 && nc <= 100)) return jsonResponse({error:'setCount must be 0-100'},400);
      lots[idx].count = nc;
    }
    if(body.setUsed !== undefined){
      const nu = parseInt(body.setUsed,10);
      if(!(nu >= 0 && nu <= lots[idx].count)) return jsonResponse({error:'setUsed out of range'},400);
      lots[idx].used = nu;
    }
    await env.USERS_KV.put(email, JSON.stringify(user));
    return jsonResponse({ ok:true, lot: lots[idx] });
  }
  return new Response('Method not allowed',{status:405});
}

async function handleAdminCalendar(request, env){
  const a = await requireAdmin(request, env);
  if(a.error) return a.error;
  const apiKey = env.CAL_COM_API_KEY;
  if(!apiKey) return jsonResponse({error:'Cal.com API key not configured'},500);
  const now = new Date();
  const thirtyDays = new Date(now.getTime() + 30*24*60*60*1000);
  const fromISO = now.toISOString();
  const toISO = thirtyDays.toISOString();
  // Cal.com v2 bookings endpoint with date range
  const url = `https://api.cal.com/v2/bookings?afterStart=${encodeURIComponent(fromISO)}&beforeStart=${encodeURIComponent(toISO)}&take=200&sortStart=asc`;
  const r = await fetch(url, {
    headers: { 'Authorization': `Bearer ${apiKey}`, 'cal-api-version': '2024-08-13' }
  });
  if(!r.ok){
    const t = await r.text();
    return jsonResponse({error:'Cal.com error', detail: t.slice(0,300)},502);
  }
  const data = await r.json();
  const bookings = (data?.data || []).map(b => ({
    uid: b.uid,
    title: b.title,
    start: b.start,
    end: b.end,
    status: b.status,
    attendees: (b.attendees||[]).map(at => ({ name: at.name, email: at.email })),
    eventType: b.eventType?.title || b.eventTypeId
  }));
  return jsonResponse({ bookings, from: fromISO, to: toISO });
}

