// Count active pre-order spots taken for a given slug (across all related programs)
async function countPreorderSpots(env, slug){
  // Walk all users, count any active pre-order with matching slug
  let taken = 0;
  let cursor;
  do {
    const page = await env.USERS_KV.list({ cursor, limit: 1000 });
    for(const k of page.keys){
      const u = await env.USERS_KV.get(k.name, 'json');
      if(!u) continue;
      for(const po of (u.preorders||[])){
        if(po.slug === slug && po.status !== 'cancelled') taken++;
      }
    }
    cursor = page.list_complete ? undefined : page.cursor;
  } while(cursor);
  return taken;
}

async function handleProgramSpots(request, env){
  const url = new URL(request.url);
  const slug = url.searchParams.get('program') || '';
  if(slug !== 'tryout-prep') return jsonResponse({error:'Unknown program slug'},400);
  const cap = 12;
  const taken = await countPreorderSpots(env, slug);
  return jsonResponse({ slug, cap, taken, remaining: Math.max(0, cap - taken) });
}

async function handleProgramConfig(request, env){
  // Public: returns the catalog so /book page can read titles/prices
  const out = {};
  for(const [k,v] of Object.entries(PROGRAMS_CATALOG)){
    out[k] = {
      label: v.label,
      priceCents: v.priceCents,
      currency: v.currency,
      stripeMode: v.stripeMode,
      needsSlot: v.needsSlot,
      preorder: !!v.preorder,
      recurringInterval: v.recurringInterval,
      description: v.description
    };
  }
  return jsonResponse({ programs: out });
}

// Ensure a recurring Price exists for a subscription program (cached via lookup_key)
async function getOrCreateRecurringPriceForProgram(env, cfg){
  const r = await fetch(`https://api.stripe.com/v1/prices/search?query=${encodeURIComponent(`lookup_key:"${cfg.lookupKey}"`)}`, {
    headers: { 'Authorization': `Bearer ${env.STRIPE_RECONCILE_KEY}` }
  });
  const data = await r.json();
  if(r.ok && data.data && data.data.length > 0) return data.data[0].id;

  // Create product + recurring price with this lookup_key
  const prodParams = new URLSearchParams();
  prodParams.set('name', cfg.label);
  if(cfg.description) prodParams.set('description', cfg.description);
  const pr = await fetch('https://api.stripe.com/v1/products', {
    method:'POST',
    headers:{ 'Authorization':`Bearer ${env.STRIPE_RECONCILE_KEY}`, 'Content-Type':'application/x-www-form-urlencoded' },
    body: prodParams
  });
  const prod = await pr.json();
  if(!pr.ok) throw new Error(`Stripe product: ${prod.error?.message||'unknown'}`);

  const priceParams = new URLSearchParams();
  priceParams.set('product', prod.id);
  priceParams.set('currency', cfg.currency);
  priceParams.set('unit_amount', String(cfg.priceCents));
  priceParams.set('recurring[interval]', cfg.recurringInterval);
  priceParams.set('lookup_key', cfg.lookupKey);
  const pricer = await fetch('https://api.stripe.com/v1/prices', {
    method:'POST',
    headers:{ 'Authorization':`Bearer ${env.STRIPE_RECONCILE_KEY}`, 'Content-Type':'application/x-www-form-urlencoded' },
    body: priceParams
  });
  const price = await pricer.json();
  if(!pricer.ok) throw new Error(`Stripe price: ${price.error?.message||'unknown'}`);
  return price.id;
}

// Create Checkout Session for a specific program
async function handleProgramCheckout(request, env){
  if(request.method !== 'POST') return new Response('Method not allowed',{status:405});
  const auth = await requireAuth(request, env);
  if(!auth) return jsonResponse({error:'Not signed in'},401);
  let body;
  try { body = await request.json(); } catch { return jsonResponse({error:'Invalid JSON'},400); }
  const programKey = (body.program||'').trim();
  const cfg = PROGRAMS_CATALOG[programKey];
  if(!cfg) return jsonResponse({error:'Unknown program'},400);

  const slotStart = (body.slotStart||'').trim();
  if(cfg.needsSlot && !slotStart) return jsonResponse({error:'Slot required for this program'},400);

  // Enforce pre-order cap
  if(cfg.preorder && cfg.preorderSlug){
    const taken = await countPreorderSpots(env, cfg.preorderSlug);
    if(taken >= cfg.preorderCap) return jsonResponse({error:`Sorry — pre-orders sold out (cap of ${cfg.preorderCap}).`},409);
  }

  try {
    const customerId = await ensureStripeCustomer(env, auth.user);
    const url = new URL(request.url);
    const origin = `${url.protocol}//${url.host}`;
    const slotParam = slotStart ? `&slot=${encodeURIComponent(slotStart)}` : '';
    const successUrl = `${origin}/book?program=${encodeURIComponent(programKey)}&step=confirm${slotParam}&session_id={CHECKOUT_SESSION_ID}`;
    const cancelUrl  = `${origin}/book?program=${encodeURIComponent(programKey)}${slotStart?'&slot='+encodeURIComponent(slotStart):''}`;

    const params = new URLSearchParams();
    params.set('customer', customerId);
    params.set('success_url', successUrl);
    params.set('cancel_url', cancelUrl);
    params.set('metadata[ti_email]', auth.user.email);
    params.set('metadata[ti_program]', programKey);
    if(slotStart) params.set('metadata[ti_slot]', slotStart);
    if(cfg.preorder) params.set('metadata[ti_preorder]', 'true');

    if(cfg.stripeMode === 'subscription'){
      const priceId = await getOrCreateRecurringPriceForProgram(env, cfg);
      params.set('mode', 'subscription');
      params.set('line_items[0][price]', priceId);
      params.set('line_items[0][quantity]', '1');
      params.set('subscription_data[metadata][ti_email]', auth.user.email);
      params.set('subscription_data[metadata][ti_program]', programKey);
      if(slotStart) params.set('subscription_data[metadata][ti_slot]', slotStart);
    } else {
      params.set('mode', 'payment');
      params.set('line_items[0][price_data][currency]', cfg.currency);
      params.set('line_items[0][price_data][product_data][name]', cfg.label);
      params.set('line_items[0][price_data][product_data][description]', cfg.description || '');
      params.set('line_items[0][price_data][unit_amount]', String(cfg.priceCents));
      params.set('line_items[0][quantity]', '1');
      params.set('payment_intent_data[metadata][ti_email]', auth.user.email);
      params.set('payment_intent_data[metadata][ti_program]', programKey);
      if(slotStart) params.set('payment_intent_data[metadata][ti_slot]', slotStart);
    }

    const r = await fetch('https://api.stripe.com/v1/checkout/sessions', {
      method:'POST',
      headers:{ 'Authorization':`Bearer ${env.STRIPE_RECONCILE_KEY}`, 'Content-Type':'application/x-www-form-urlencoded' },
      body: params
    });
    const data = await r.json();
    if(!r.ok || !data.url) return jsonResponse({error: data.error?.message || 'Stripe error'},500);
    return jsonResponse({ url: data.url });
  } catch(e){
    return jsonResponse({error: 'Checkout error: '+(e.message||'unknown')}, 500);
  }
}

// Helper: find all dates of `weekday` (0=Sun..6=Sat) between two Date objects (inclusive of from)
function mondaysBetween(fromDate, toDate, weekday){
  const out = [];
  const d = new Date(fromDate);
  while(d <= toDate){
    if(d.getDay() === weekday) out.push(new Date(d));
    d.setDate(d.getDate()+1);
  }
  return out;
}

// Create a Cal.com booking for a given user at a given ISO start
async function createCalBookingForUser(env, user, eventTypeId, startISO, extraMeta){
  const attendeeName = (user.parentName || user.athleteName || user.email).trim();
  const payload = {
    eventTypeId,
    start: startISO,
    attendee: { name: attendeeName, email: user.email, timeZone:'America/Toronto', language:'en' },
    metadata: Object.assign({
      ti_email: user.email,
      athlete_name: user.athleteName || '',
      athlete_dob: user.athleteDob || '',
      level: user.level || ''
    }, extraMeta || {})
  };
  const r = await fetch('https://api.cal.com/v2/bookings', {
    method:'POST',
    headers:{ 'Authorization':`Bearer ${env.CAL_COM_API_KEY}`, 'cal-api-version':'2024-08-13', 'Content-Type':'application/json' },
    body: JSON.stringify(payload)
  });
  const body = await r.json();
  if(!r.ok){
    return { ok:false, error: body?.error?.message || body?.message || 'Cal.com error', detail: body };
  }
  const b = body?.data || body;
  return { ok:true, uid: b?.uid || b?.id || 'unknown' };
}

// Claim handler — verifies Stripe payment and books appropriate Cal.com slots
async function handleClaimProgramBooking(request, env){
  const auth = await requireAuth(request, env);
  if(!auth) return jsonResponse({error:'Not signed in'},401);
  const url = new URL(request.url);
  const sessionId = url.searchParams.get('session_id');
  const programKey = url.searchParams.get('program');
  const slotStart = url.searchParams.get('slot');
  if(!sessionId || !sessionId.startsWith('cs_')) return jsonResponse({error:'Invalid session id'},400);
  const cfg = PROGRAMS_CATALOG[programKey];
  if(!cfg) return jsonResponse({error:'Unknown program'},400);

  // Verify Stripe session
  const r = await fetch(`https://api.stripe.com/v1/checkout/sessions/${sessionId}`, {
    headers:{ 'Authorization':`Bearer ${env.STRIPE_RECONCILE_KEY}` }
  });
  const cs = await r.json();
  if(!r.ok) return jsonResponse({error: cs.error?.message||'Could not retrieve session'},400);
  if(cs.metadata?.ti_email !== auth.user.email) return jsonResponse({error:'Session does not belong to this account'},403);
  if(cs.payment_status !== 'paid') return jsonResponse({ claimed:false, payment_status:cs.payment_status });

  const user = await env.USERS_KV.get(auth.user.email, 'json');
  const stripeRef = cs.subscription || cs.payment_intent || cs.id;

  // Idempotency
  const already = (user.bookings||[]).find(b => b.stripeRef === stripeRef)
               || (user.preorders||[]).find(p => p.stripeRef === stripeRef);
  if(already){
    return jsonResponse({ claimed:true, alreadyHandled:true, program:programKey });
  }

  // Pre-order programs: record pre-order, no Cal.com booking
  if(cfg.preorder){
    user.preorders = (user.preorders||[]).concat([{
      id: newToken(8),
      program: programKey,
      slug: cfg.preorderSlug,
      stripeRef,
      mode: cfg.stripeMode,
      priceCents: cfg.priceCents,
      paidAt: Date.now(),
      status: 'reserved'
    }]);
    await env.USERS_KV.put(user.email, JSON.stringify(user));
    // Notify Coach (best-effort)
    try { await sendCoachAlert(env, 'program_preorder', {
      user, programKey, programLabel: cfg.label
    }); } catch(_){}
    return jsonResponse({ claimed:true, preorder:true, program: programKey, message:'Spot reserved. Program starts in October.' });
  }

  // Subscription with weekly auto-book (Monday Monthly)
  if(cfg.stripeMode === 'subscription' && cfg.autoBookWeeklyOn !== undefined){
    // Period from now (or picked start) → end of current billing cycle (~30 days)
    const start = slotStart ? new Date(slotStart) : new Date();
    const end = new Date(start);
    end.setMonth(end.getMonth() + 1);
    const startTimeOfDay = slotStart ? slotStart.slice(11,19) : '18:00:00';
    const tz = '-04:00'; // Eastern
    const mondays = mondaysBetween(start, end, cfg.autoBookWeeklyOn);
    const created = [];
    const errors = [];
    for(const m of mondays){
      const iso = `${m.toISOString().slice(0,10)}T${startTimeOfDay}.000${tz}`;
      const res = await createCalBookingForUser(env, user, cfg.calEventId, iso, {
        ti_program: programKey, ti_stripe_ref: stripeRef
      });
      if(res.ok){
        created.push({ calBookingUid: res.uid, startTime: iso, bookedAt: Date.now(),
                       status:'accepted', stripeRef, source: programKey });
      } else {
        errors.push({ iso, error: res.error });
      }
    }
    user.bookings = (user.bookings||[]).concat(created);
    user.subscription = {
      active: true, stripeSubscriptionId: cs.subscription,
      program: programKey, lastInvoicedAt: Date.now()
    };
    await env.USERS_KV.put(user.email, JSON.stringify(user));
    // Notify Coach (best-effort)
    try { await sendCoachAlert(env, 'program_subscription', {
      user, programKey, programLabel: cfg.label, bookingsCreated: created.length
    }); } catch(_){}
    return jsonResponse({ claimed:true, program:programKey, bookingsCreated: created.length,
                          errors: errors.length ? errors : undefined });
  }

  // Single-payment with slot (1-on-1, Monday Drop-In)
  if(cfg.needsSlot && slotStart){
    const res = await createCalBookingForUser(env, user, cfg.calEventId, slotStart, {
      ti_program: programKey, ti_stripe_ref: stripeRef
    });
    if(!res.ok){
      return jsonResponse({ claimed:false, paid:true, calError: res.error, contact:'Crosbyathletics321@gmail.com' });
    }
    user.bookings = (user.bookings||[]).concat([{
      calBookingUid: res.uid, startTime: slotStart, bookedAt: Date.now(),
      status:'accepted', stripeRef, source: programKey
    }]);
    await env.USERS_KV.put(user.email, JSON.stringify(user));
    // Notify Coach (best-effort)
    try { await sendCoachAlert(env, 'program_single', {
      user, programKey, programLabel: cfg.label, slotStart, calBookingUid: res.uid
    }); } catch(_){}
    return jsonResponse({ claimed:true, program:programKey, bookingUid: res.uid, slotStart });
  }

  // Generic payment-only programs (e.g., camps) — record the payment as a booking
  if(!cfg.needsSlot && !cfg.creditPack && !cfg.preorder){
    user.bookings = (user.bookings||[]).concat([{
      calBookingUid: null,
      startTime: null,
      bookedAt: Date.now(),
      status: 'paid',
      stripeRef,
      source: programKey
    }]);
    await env.USERS_KV.put(user.email, JSON.stringify(user));
    // If this payment was for a camp the parent already registered for via the
    // Camp Details form, notify Coach that payment cleared. Best-effort.
    if(programKey === 'camps-morning' || programKey === 'camps-afternoon'){
      const reg = (user.campRegistrations||[]).find(r => r.camp === programKey);
      if(reg){
        try { await sendCampNotification(env, user, reg, 'payment_confirmed'); } catch(_){}
      }
    }
    return jsonResponse({ claimed:true, program:programKey, paid:true });
  }
  return jsonResponse({ claimed:false, error:'Unsupported program shape' }, 500);
}

