// Reuse the existing stripeApi() helper for low-level Stripe REST calls.
// Returns parsed JSON. Throws on non-2xx.

const RECURRING_LOOKUP_KEY = 'ti_session_75_monthly_cad';

async function ensureStripeCustomer(env, user){
  if(user.stripeCustomerId) return user.stripeCustomerId;
  const params = new URLSearchParams();
  params.set('email', user.email);
  if(user.parentName) params.set('name', user.parentName);
  if(user.phone) params.set('phone', user.phone);
  params.set('metadata[ti_email]', user.email);
  if(user.athleteName) params.set('metadata[athlete_name]', user.athleteName);
  const r = await fetch('https://api.stripe.com/v1/customers', {
    method:'POST',
    headers:{ 'Authorization':`Bearer ${env.STRIPE_RECONCILE_KEY}`, 'Content-Type':'application/x-www-form-urlencoded' },
    body: params
  });
  const body = await r.json();
  if(!r.ok) throw new Error(`Stripe customer create ${r.status}: ${body.error?.message||'unknown'}`);
  // Persist on user
  user.stripeCustomerId = body.id;
  await env.USERS_KV.put(user.email, JSON.stringify(user));
  return body.id;
}

async function getOrCreateRecurringPrice(env){
  // First, search for an existing price with our lookup_key
  const r = await fetch(`https://api.stripe.com/v1/prices/search?query=${encodeURIComponent(`lookup_key:"${RECURRING_LOOKUP_KEY}"`)}`, {
    headers:{ 'Authorization':`Bearer ${env.STRIPE_RECONCILE_KEY}` }
  });
  const data = await r.json();
  if(r.ok && data.data && data.data.length > 0){
    return data.data[0].id;
  }
  // Not found — create a product + recurring price
  const prodParams = new URLSearchParams();
  prodParams.set('name', 'TI Baseball 1-on-1 Session');
  prodParams.set('description', '60-min private 1-on-1 baseball training session with Coach. $75 each.');
  const pr = await fetch('https://api.stripe.com/v1/products', {
    method:'POST',
    headers:{ 'Authorization':`Bearer ${env.STRIPE_RECONCILE_KEY}`, 'Content-Type':'application/x-www-form-urlencoded' },
    body: prodParams
  });
  const prod = await pr.json();
  if(!pr.ok) throw new Error(`Stripe product create: ${prod.error?.message||'unknown'}`);

  const priceParams = new URLSearchParams();
  priceParams.set('product', prod.id);
  priceParams.set('currency', 'cad');
  priceParams.set('unit_amount', '7500');
  priceParams.set('recurring[interval]', 'month');
  priceParams.set('lookup_key', RECURRING_LOOKUP_KEY);
  priceParams.set('nickname', '1-on-1 Session ($75/mo, qty=#sessions)');
  const pricer = await fetch('https://api.stripe.com/v1/prices', {
    method:'POST',
    headers:{ 'Authorization':`Bearer ${env.STRIPE_RECONCILE_KEY}`, 'Content-Type':'application/x-www-form-urlencoded' },
    body: priceParams
  });
  const price = await pricer.json();
  if(!pricer.ok) throw new Error(`Stripe price create: ${price.error?.message||'unknown'}`);
  return price.id;
}

async function handleCheckout(request, env){
  if(request.method !== 'POST') return new Response('Method not allowed',{status:405});
  const auth = await requireAuth(request, env);
  if(!auth) return jsonResponse({error:'Not signed in'},401);
  let body;
  try { body = await request.json(); } catch { return jsonResponse({error:'Invalid JSON'},400); }
  const mode = body.mode === 'monthly' ? 'monthly' : 'one_time';
  const quantity = parseInt(body.quantity, 10);
  if(!(quantity >= 4 && quantity <= 12)) return jsonResponse({error:'Quantity must be between 4 and 12'},400);

  const url = new URL(request.url);
  const origin = `${url.protocol}//${url.host}`;
  const successUrl = `${origin}/dashboard?purchase=success&session_id={CHECKOUT_SESSION_ID}`;
  const cancelUrl  = `${origin}/dashboard/buy`;

  const customerId = await ensureStripeCustomer(env, auth.user);

  const params = new URLSearchParams();
  params.set('customer', customerId);
  params.set('success_url', successUrl);
  params.set('cancel_url', cancelUrl);
  params.set('metadata[ti_email]', auth.user.email);
  params.set('metadata[ti_pack_size]', String(quantity));
  params.set('metadata[ti_mode]', mode);
  params.set('allow_promotion_codes', 'true');

  if(mode === 'monthly'){
    const priceId = await getOrCreateRecurringPrice(env);
    params.set('mode', 'subscription');
    params.set('line_items[0][price]', priceId);
    params.set('line_items[0][quantity]', String(quantity));
    params.set('subscription_data[metadata][ti_email]', auth.user.email);
    params.set('subscription_data[metadata][ti_pack_size]', String(quantity));
  } else {
    params.set('mode', 'payment');
    params.set('line_items[0][price_data][currency]', 'cad');
    params.set('line_items[0][price_data][product_data][name]', `TI Baseball — ${quantity} Session Pack`);
    params.set('line_items[0][price_data][product_data][description]', '1-on-1 training sessions with Coach. Expires 30 days after purchase.');
    params.set('line_items[0][price_data][unit_amount]', '7500');
    params.set('line_items[0][quantity]', String(quantity));
    params.set('payment_intent_data[metadata][ti_email]', auth.user.email);
    params.set('payment_intent_data[metadata][ti_pack_size]', String(quantity));
  }

  const r = await fetch('https://api.stripe.com/v1/checkout/sessions', {
    method:'POST',
    headers:{ 'Authorization':`Bearer ${env.STRIPE_RECONCILE_KEY}`, 'Content-Type':'application/x-www-form-urlencoded' },
    body: params
  });
  const data = await r.json();
  if(!r.ok || !data.url){
    return jsonResponse({error: data.error?.message || 'Stripe checkout error'}, 500);
  }
  return jsonResponse({ url: data.url });
}

async function handleClaimPurchase(request, env){
  const auth = await requireAuth(request, env);
  if(!auth) return jsonResponse({error:'Not signed in'},401);
  const url = new URL(request.url);
  const sessionId = url.searchParams.get('session_id');
  if(!sessionId || !sessionId.startsWith('cs_')) return jsonResponse({error:'Invalid session id'},400);

  // Retrieve the Checkout Session from Stripe
  const r = await fetch(`https://api.stripe.com/v1/checkout/sessions/${sessionId}`, {
    headers:{ 'Authorization':`Bearer ${env.STRIPE_RECONCILE_KEY}` }
  });
  const cs = await r.json();
  if(!r.ok) return jsonResponse({error:cs.error?.message||'Could not retrieve session'},400);

  // Verify ownership via metadata
  const sessEmail = cs.metadata?.ti_email;
  if(!sessEmail || sessEmail !== auth.user.email){
    return jsonResponse({error:'Session does not belong to this account'},403);
  }
  // Verify payment
  if(cs.payment_status !== 'paid'){
    return jsonResponse({ claimed:false, payment_status: cs.payment_status });
  }
  const packSize = parseInt(cs.metadata?.ti_pack_size||'0', 10);
  if(!(packSize >= 4 && packSize <= 12)) return jsonResponse({error:'Invalid pack size in session'},400);
  const csMode = cs.metadata?.ti_mode || 'one_time';

  // Idempotency — refresh user, check if this stripeId is already credited
  const user = await env.USERS_KV.get(auth.user.email, 'json');
  const stripeRef = csMode === 'monthly' ? (cs.subscription || cs.id) : (cs.payment_intent || cs.id);
  const existing = (user.credits||[]).find(c => c.stripeId === stripeRef);
  if(existing){
    return jsonResponse({ claimed:true, alreadyCredited:true, creditsAvailable: totalAvailable(user) });
  }

  const now = Date.now();
  const lot = {
    id: newToken(8),
    count: packSize,
    used: 0,
    purchasedAt: now,
    expiresAt: now + 30*24*60*60*1000,
    source: csMode,
    stripeId: stripeRef
  };
  user.credits = (user.credits||[]).concat([lot]);
  if(csMode === 'monthly'){
    user.subscription = {
      active: true,
      stripeSubscriptionId: cs.subscription,
      packSize,
      lastInvoicedAt: now
    };
  }
  await env.USERS_KV.put(user.email, JSON.stringify(user));
  // Notify Coach of the new pack purchase (best-effort)
  try { await sendCoachAlert(env, 'session_purchase', { user, packSize, mode: csMode, expiresAt: lot.expiresAt }); } catch(_){}
  return jsonResponse({ claimed:true, creditsAvailable: totalAvailable(user), packSize, expiresAt: lot.expiresAt });
}

function totalAvailable(user){
  const now = Date.now();
  let n = 0;
  for(const lot of (user.credits||[])){
    if((lot.count - (lot.used||0)) > 0 && lot.expiresAt > now){
      n += lot.count - (lot.used||0);
    }
  }
  return n;
}

// ==== single_book_handlers.js ====
// ============================================================
// SINGLE-SESSION GUEST CHECKOUT  —  $90 one-off booking
// ============================================================

async function handleSingleCheckout(request, env){
  if(request.method !== 'POST') return new Response('Method not allowed',{status:405});
  const auth = await requireAuth(request, env);
  if(!auth) return jsonResponse({error:'Not signed in'},401);
  let body;
  try { body = await request.json(); } catch { return jsonResponse({error:'Invalid JSON'},400); }
  const slotStart = (body.slotStart||'').trim();
  if(!slotStart || !/^\d{4}-\d{2}-\d{2}T/.test(slotStart)) return jsonResponse({error:'Missing slot time'},400);

  try {
    const customerId = await ensureStripeCustomer(env, auth.user);
    const url = new URL(request.url);
    const origin = `${url.protocol}//${url.host}`;
    const successUrl = `${origin}/book?step=confirm&slot=${encodeURIComponent(slotStart)}&session_id={CHECKOUT_SESSION_ID}`;
    const cancelUrl  = `${origin}/book?step=pay&slot=${encodeURIComponent(slotStart)}`;

    const params = new URLSearchParams();
    params.set('customer', customerId);
    params.set('success_url', successUrl);
    params.set('cancel_url', cancelUrl);
    params.set('mode', 'payment');
    params.set('line_items[0][price_data][currency]', 'cad');
    params.set('line_items[0][price_data][product_data][name]', 'TI Baseball — 1-on-1 Session');
    params.set('line_items[0][price_data][product_data][description]', `60-min 1-on-1 with Coach at ${new Date(slotStart).toLocaleString('en-CA',{weekday:'long',month:'long',day:'numeric',hour:'numeric',minute:'2-digit'})}`);
    params.set('line_items[0][price_data][unit_amount]', '9000');
    params.set('line_items[0][quantity]', '1');
    params.set('metadata[ti_email]', auth.user.email);
    params.set('metadata[ti_mode]', 'single_session');
    params.set('metadata[ti_slot]', slotStart);
    params.set('payment_intent_data[metadata][ti_email]', auth.user.email);
    params.set('payment_intent_data[metadata][ti_slot]', slotStart);

    const r = await fetch('https://api.stripe.com/v1/checkout/sessions', {
      method:'POST',
      headers:{ 'Authorization':`Bearer ${env.STRIPE_RECONCILE_KEY}`, 'Content-Type':'application/x-www-form-urlencoded' },
      body: params
    });
    const data = await r.json();
    if(!r.ok || !data.url){
      return jsonResponse({error: data.error?.message || 'Stripe error'},500);
    }
    return jsonResponse({ url: data.url });
  } catch(e){
    return jsonResponse({error: 'Checkout error: '+(e.message||'unknown')}, 500);
  }
}

async function handleClaimSingleBooking(request, env){
  const auth = await requireAuth(request, env);
  if(!auth) return jsonResponse({error:'Not signed in'},401);
  const url = new URL(request.url);
  const sessionId = url.searchParams.get('session_id');
  const slotStart = url.searchParams.get('slot');
  if(!sessionId || !sessionId.startsWith('cs_')) return jsonResponse({error:'Invalid session id'},400);
  if(!slotStart) return jsonResponse({error:'Missing slot'},400);

  // Verify payment with Stripe
  const r = await fetch(`https://api.stripe.com/v1/checkout/sessions/${sessionId}`, {
    headers:{ 'Authorization':`Bearer ${env.STRIPE_RECONCILE_KEY}` }
  });
  const cs = await r.json();
  if(!r.ok) return jsonResponse({error: cs.error?.message||'Could not retrieve session'},400);
  if(cs.metadata?.ti_email !== auth.user.email) return jsonResponse({error:'Session does not belong to this account'},403);
  if(cs.payment_status !== 'paid') return jsonResponse({ claimed:false, payment_status:cs.payment_status });
  if(cs.metadata?.ti_mode !== 'single_session') return jsonResponse({error:'Wrong session type'},400);

  // Idempotency — has this session id already been booked?
  const user = await env.USERS_KV.get(auth.user.email, 'json');
  const stripeRef = cs.payment_intent || cs.id;
  const already = (user.bookings||[]).find(b => b.stripeRef === stripeRef);
  if(already){
    return jsonResponse({ claimed:true, alreadyBooked:true, bookingUid: already.calBookingUid, slotStart: already.startTime });
  }

  // Create Cal.com booking
  const attendeeName = (user.parentName || user.athleteName || user.email).trim();
  const bookingPayload = {
    eventTypeId: CAL_ONE_ON_ONE_EVENT_ID,
    start: slotStart,
    attendee: { name: attendeeName, email: user.email, timeZone: 'America/Toronto', language: 'en' },
    metadata: {
      ti_email: user.email,
      ti_mode: 'single_session',
      ti_paid: 'true',
      ti_stripe_ref: stripeRef,
      athlete_name: user.athleteName || '',
      athlete_dob: user.athleteDob || '',
      level: user.level || ''
    }
  };
  const cr = await fetch('https://api.cal.com/v2/bookings', {
    method:'POST',
    headers:{ 'Authorization':`Bearer ${env.CAL_COM_API_KEY}`, 'cal-api-version':'2024-08-13', 'Content-Type':'application/json' },
    body: JSON.stringify(bookingPayload)
  });
  const calBody = await cr.json();
  if(!cr.ok){
    // Slot might no longer be available — refund needed
    const detail = calBody?.error?.message || calBody?.message || 'Could not create Cal.com booking. Coach will contact you to refund or reschedule.';
    return jsonResponse({ claimed:false, paid:true, calError: detail, contact:'Crosbyathletics321@gmail.com' }, 200);
  }
  const calBooking = calBody?.data || calBody;
  const calUid = calBooking?.uid || calBooking?.id || 'unknown';

  user.bookings = (user.bookings||[]).concat([{
    calBookingUid: calUid,
    startTime: slotStart,
    creditLotId: null,
    bookedAt: Date.now(),
    status: 'accepted',
    stripeRef,
    source: 'single_session_$90'
  }]);
  await env.USERS_KV.put(user.email, JSON.stringify(user));
  // Notify Coach (best-effort)
  try { await sendCoachAlert(env, 'single_session_booked', { user, slotStart, calBookingUid: calUid }); } catch(_){}
  return jsonResponse({ claimed:true, bookingUid: calUid, slotStart });
}

// ==== booking_handlers.js ====
// ============================================================
// BOOKING HANDLERS — book Cal.com slots against credit balance
// ============================================================
const CAL_ONE_ON_ONE_EVENT_ID = 6031855;  // 1-on-1 60-min event
const CAL_API_VERSION = '2024-08-13';

async function calApiV2(path, env, init){
  const url = path.startsWith('http') ? path : `https://api.cal.com${path}`;
  const headers = Object.assign({
    'Authorization': `Bearer ${env.CAL_COM_API_KEY}`,
    'cal-api-version': CAL_API_VERSION,
    'Content-Type': 'application/json'
  }, (init && init.headers) || {});
  const r = await fetch(url, Object.assign({}, init, { headers }));
  const txt = await r.text();
  let body; try { body = JSON.parse(txt); } catch { body = { raw: txt }; }
  return { status: r.status, ok: r.ok, body };
}

async function handleAvailableSlots(request, env){
  const auth = await requireAuth(request, env);
  if(!auth) return jsonResponse({error:'Not signed in'},401);
  const url = new URL(request.url);
  const start = url.searchParams.get('start') || new Date().toISOString();
  const endParam = url.searchParams.get('end');
  const endDate = endParam ? new Date(endParam) : new Date(Date.now() + 14*24*60*60*1000);
  const endISO = endDate.toISOString();
  const params = new URLSearchParams({
    eventTypeId: String(CAL_ONE_ON_ONE_EVENT_ID),
    start, end: endISO,
    timeZone: 'America/Toronto'
  });
  const r = await calApiV2(`/v2/slots?${params}`, env, { method:'GET' });
  if(!r.ok) return jsonResponse({error:'Cal.com slots error', detail: r.body },502);
  // Cal returns { data: { 'YYYY-MM-DD': [ { start: '...' }, ... ] } }
  const data = r.body?.data || {};
  return jsonResponse({ slots: data, eventTypeId: CAL_ONE_ON_ONE_EVENT_ID });
}

function pickEarliestExpiringLot(user){
  const now = Date.now();
  let best = null;
  for(const lot of (user.credits||[])){
    const rem = (lot.count||0) - (lot.used||0);
    if(rem <= 0) continue;
    if(lot.expiresAt <= now) continue;
    if(!best || lot.expiresAt < best.expiresAt) best = lot;
  }
  return best;
}

async function handleBookSession(request, env){
  if(request.method !== 'POST') return new Response('Method not allowed',{status:405});
  const auth = await requireAuth(request, env);
  if(!auth) return jsonResponse({error:'Not signed in'},401);
  let body;
  try { body = await request.json(); } catch { return jsonResponse({error:'Invalid JSON'},400); }
  const startISO = (body.start||'').trim();
  if(!startISO || !/^\d{4}-\d{2}-\d{2}T/.test(startISO)) return jsonResponse({error:'Missing or invalid start time'},400);

  // Re-read user to make sure credits are fresh
  const user = await env.USERS_KV.get(auth.user.email,'json');
  if(!user) return jsonResponse({error:'User not found'},404);

  const lot = pickEarliestExpiringLot(user);
  if(!lot) return jsonResponse({error:'No active sessions available. Buy a pack first.'},402);

  // Compose booking — attendee details from user record
  const attendeeName = (user.parentName || user.athleteName || user.email).trim();
  const bookingPayload = {
    eventTypeId: CAL_ONE_ON_ONE_EVENT_ID,
    start: startISO,
    attendee: {
      name: attendeeName,
      email: user.email,
      timeZone: 'America/Toronto',
      language: 'en'
    },
    metadata: {
      ti_email: user.email,
      ti_lot_id: lot.id,
      ti_credit_used: true,
      athlete_name: user.athleteName || '',
      athlete_dob: user.athleteDob || '',
      level: user.level || ''
    }
  };

  const r = await calApiV2('/v2/bookings', env, {
    method:'POST',
    body: JSON.stringify(bookingPayload)
  });
  if(!r.ok){
    const detail = r.body?.error?.message || r.body?.error || r.body?.message || 'Cal.com booking failed';
    return jsonResponse({error:'Booking failed', detail},502);
  }
  const calBooking = r.body?.data || r.body;
  const calUid = calBooking?.uid || calBooking?.id || 'unknown';

  // Decrement the lot, record the booking
  const lots = user.credits;
  const idx = lots.findIndex(l => l.id === lot.id);
  if(idx >= 0){
    lots[idx].used = (lots[idx].used||0) + 1;
  }
  user.bookings = (user.bookings || []).concat([{
    calBookingUid: calUid,
    startTime: startISO,
    creditLotId: lot.id,
    bookedAt: Date.now(),
    status: 'accepted'
  }]);
  await env.USERS_KV.put(user.email, JSON.stringify(user));

  // Notify Coach (best-effort)
  try { await sendCoachAlert(env, 'credit_booked', {
    user, slotStart: startISO, calBookingUid: calUid,
    creditsLeft: (lots[idx].count - lots[idx].used)
  }); } catch(_){}

  return jsonResponse({
    ok: true,
    bookingUid: calUid,
    startTime: startISO,
    remainingCredits: (lots[idx].count - lots[idx].used)
  });
}

async function handleMyBookings(request, env){
  const auth = await requireAuth(request, env);
  if(!auth) return jsonResponse({error:'Not signed in'},401);
  const user = await env.USERS_KV.get(auth.user.email,'json');
  const bookings = (user.bookings||[]).slice().sort((a,b)=> (b.bookedAt||0) - (a.bookedAt||0));
  return jsonResponse({ bookings });
}

// ==== stripe_webhook.js ====
// ============================================================
// STRIPE WEBHOOK  —  handles recurring renewals + cancellations
// ============================================================
// Signing secret comes from env.STRIPE_WEBHOOK_SECRET (set after Coach
// creates the webhook endpoint in Stripe Dashboard).

async function verifyStripeSignature(rawBody, sigHeader, secret){
  if(!secret || !sigHeader) return false;
  // Parse: "t=TIMESTAMP,v1=HASH,v1=HASH2"
  const parts = sigHeader.split(',').map(p => p.split('='));
  const timestamp = parts.find(p => p[0]==='t')?.[1];
  const v1Hashes = parts.filter(p => p[0]==='v1').map(p => p[1]);
  if(!timestamp || v1Hashes.length === 0) return false;
  // Reject if timestamp is more than 5 minutes old (replay attack defense)
  const ageSec = (Date.now()/1000) - parseInt(timestamp,10);
  if(Math.abs(ageSec) > 300) return false;

  const enc = new TextEncoder();
  const key = await crypto.subtle.importKey(
    'raw', enc.encode(secret), { name:'HMAC', hash:'SHA-256' }, false, ['sign']
  );
  const expectedBytes = await crypto.subtle.sign('HMAC', key, enc.encode(`${timestamp}.${rawBody}`));
  const expected = Array.from(new Uint8Array(expectedBytes)).map(b => b.toString(16).padStart(2,'0')).join('');

  // Constant-time compare against each v1 hash
  for(const got of v1Hashes){
    if(got.length !== expected.length) continue;
    let diff = 0;
    for(let i=0; i<got.length; i++) diff |= got.charCodeAt(i) ^ expected.charCodeAt(i);
    if(diff === 0) return true;
  }
  return false;
}

// Look up user by Stripe customer id (or email metadata)
async function userByStripeCustomer(env, stripeCustomerId, emailFallback){
  if(emailFallback){
    const u = await env.USERS_KV.get(emailFallback.toLowerCase(), 'json');
    if(u) return u;
  }
  // Walk users for matching stripeCustomerId — slow path, acceptable for low volume
  let cursor;
  do {
    const page = await env.USERS_KV.list({ cursor, limit:1000 });
    for(const k of page.keys){
      const u = await env.USERS_KV.get(k.name, 'json');
      if(u && u.stripeCustomerId === stripeCustomerId) return u;
    }
    cursor = page.list_complete ? undefined : page.cursor;
  } while(cursor);
  return null;
}

async function fetchStripeSubscription(env, subId){
  const r = await fetch(`https://api.stripe.com/v1/subscriptions/${subId}`, {
    headers:{ 'Authorization':`Bearer ${env.STRIPE_RECONCILE_KEY}` }
  });
  return r.ok ? r.json() : null;
}

// Auto-book recurring weekly slots for a subscription's current billing period
async function autoBookWeeklySlotsForRenewal(env, user, cfg, programKey, subscription, stripeRef){
  const periodStart = subscription.current_period_start ? new Date(subscription.current_period_start * 1000) : new Date();
  const periodEnd   = subscription.current_period_end   ? new Date(subscription.current_period_end   * 1000) : new Date(Date.now() + 30*86400000);
  // Try to honor the weekday + time-of-day from subscription metadata (slot picked at signup)
  const seedSlot = subscription.metadata?.ti_slot;
  let timeOfDay = '18:00:00';
  let weekday = cfg.autoBookWeeklyOn;
  if(seedSlot){
    timeOfDay = seedSlot.slice(11,19);
    const dow = new Date(seedSlot).getDay();
    if(typeof dow === 'number') weekday = dow;
  }
  const tz = '-04:00';

  const mondays = mondaysBetween(periodStart, periodEnd, weekday);
  const created = [];
  const errors = [];
  for(const m of mondays){
    const iso = `${m.toISOString().slice(0,10)}T${timeOfDay}.000${tz}`;
    // Idempotency — skip if user already has a booking for this slot via this subscription
    const dup = (user.bookings||[]).find(b => b.startTime === iso && b.stripeRef === subscription.id);
    if(dup) continue;
    const res = await createCalBookingForUser(env, user, cfg.calEventId, iso, {
      ti_program: programKey, ti_stripe_ref: subscription.id, ti_renewal: 'true'
    });
    if(res.ok){
      created.push({ calBookingUid: res.uid, startTime: iso, bookedAt: Date.now(),
                     status:'accepted', stripeRef: subscription.id, source: programKey + '_renewal' });
    } else {
      errors.push({ iso, error: res.error });
    }
  }
  if(created.length){
    user.bookings = (user.bookings||[]).concat(created);
  }
  user.subscription = Object.assign(user.subscription||{}, {
    active: true,
    stripeSubscriptionId: subscription.id,
    program: programKey,
    lastInvoicedAt: Date.now(),
    currentPeriodEnd: subscription.current_period_end
  });
  await env.USERS_KV.put(user.email, JSON.stringify(user));
  return { created: created.length, errors };
}

async function handleStripeWebhook(request, env){
  if(request.method !== 'POST') return new Response('Method not allowed',{status:405});
  const rawBody = await request.text();
  const sigHeader = request.headers.get('stripe-signature') || '';
  const secret = env.STRIPE_WEBHOOK_SECRET;

  // Verify signature
  const ok = await verifyStripeSignature(rawBody, sigHeader, secret);
  if(!ok){
    if(!secret){
      // Helpful one-liner if Coach hasn't set the secret yet
      console.log('webhook received but STRIPE_WEBHOOK_SECRET not configured');
      return new Response('Webhook secret not configured', { status: 503 });
    }
    return new Response('Invalid signature', { status: 400 });
  }

  let event;
  try { event = JSON.parse(rawBody); } catch { return new Response('Bad JSON',{status:400}); }

  const type = event.type;
  const obj = event.data?.object || {};
  console.log('webhook event:', type, 'id:', event.id);

  try {
    switch(type){
      case 'invoice.paid': {
        // Recurring renewal (or first paid invoice for new subscription)
        const subId = obj.subscription;
        if(!subId){ return new Response('ok (no subscription)',{status:200}); }
        const sub = await fetchStripeSubscription(env, subId);
        if(!sub){ return new Response('ok (sub not found)',{status:200}); }
        const programKey = sub.metadata?.ti_program;
        const email = sub.metadata?.ti_email || obj.customer_email;
        if(!programKey || !email){ return new Response('ok (missing metadata)',{status:200}); }
        const cfg = PROGRAMS_CATALOG[programKey];
        if(!cfg){ return new Response('ok (unknown program)',{status:200}); }
        const user = await userByStripeCustomer(env, obj.customer, email);
        if(!user){ return new Response('ok (user not found)',{status:200}); }

        // Skip the first invoice — that's handled by /api/claim-program-booking
        // Use billing_reason to distinguish:
        //   subscription_create   = first invoice (already handled by claim endpoint)
        //   subscription_cycle    = recurring renewal (we handle here)
        if(obj.billing_reason === 'subscription_create'){
          // Still update lastInvoicedAt for record-keeping
          user.subscription = Object.assign(user.subscription||{}, {
            active:true, stripeSubscriptionId: subId, program: programKey,
            lastInvoicedAt: Date.now(), currentPeriodEnd: sub.current_period_end
          });
          await env.USERS_KV.put(user.email, JSON.stringify(user));
          return new Response('ok (first invoice, claim handles it)',{status:200});
        }

        // Renewal — re-book this period's slots OR top up credit pack
        if(cfg.autoBookWeeklyOn !== undefined && cfg.calEventId){
          const r = await autoBookWeeklySlotsForRenewal(env, user, cfg, programKey, sub, subId);
          return new Response(`ok (renewal: ${r.created} sessions booked)`, {status:200});
        }

        // For credit-pack subscriptions (1-on-1 monthly), add a new credit lot
        if(programKey === 'one-on-one-monthly-pack' || cfg.creditPack){
          const packSize = parseInt(sub.metadata?.ti_pack_size || '4', 10);
          const now = Date.now();
          user.credits = (user.credits||[]).concat([{
            id: newToken(8), count: packSize, used: 0,
            purchasedAt: now, expiresAt: now + 30*24*60*60*1000,
            source: 'monthly_renewal', stripeId: subId+':'+obj.id
          }]);
          user.subscription = Object.assign(user.subscription||{}, {
            active:true, stripeSubscriptionId: subId, lastInvoicedAt: now,
            currentPeriodEnd: sub.current_period_end
          });
          await env.USERS_KV.put(user.email, JSON.stringify(user));
          return new Response(`ok (renewal: ${packSize} credits added)`, {status:200});
        }

        // Other subscriptions — just update timestamp
        user.subscription = Object.assign(user.subscription||{}, {
          active:true, stripeSubscriptionId: subId, lastInvoicedAt: Date.now(),
          currentPeriodEnd: sub.current_period_end
        });
        await env.USERS_KV.put(user.email, JSON.stringify(user));
        return new Response('ok (renewal noted)', {status:200});
      }

      case 'invoice.payment_failed': {
        const email = obj.customer_email;
        const subId = obj.subscription;
        if(!email) return new Response('ok (no email)',{status:200});
        const user = await env.USERS_KV.get(email.toLowerCase(),'json');
        if(!user) return new Response('ok (user not found)',{status:200});
        user.subscription = Object.assign(user.subscription||{}, {
          active: false, paymentFailedAt: Date.now()
        });
        await env.USERS_KV.put(user.email, JSON.stringify(user));
        return new Response('ok (subscription marked inactive)',{status:200});
      }

      case 'customer.subscription.deleted': {
        const email = obj.metadata?.ti_email;
        if(!email) return new Response('ok (no email metadata)',{status:200});
        const user = await env.USERS_KV.get(email.toLowerCase(),'json');
        if(!user) return new Response('ok (user not found)',{status:200});
        user.subscription = Object.assign(user.subscription||{}, {
          active: false, cancelledAt: Date.now()
        });
        await env.USERS_KV.put(user.email, JSON.stringify(user));
        return new Response('ok (cancellation recorded)',{status:200});
      }

      case 'checkout.session.completed': {
        // Safety net — usually /api/claim-program-booking or /api/claim-purchase
        // handles this via redirect. Only act if the user closed browser before
        // the claim ran (no booking/credit lot yet).
        const cs = obj;
        const email = cs.metadata?.ti_email;
        if(!email){ return new Response('ok (no ti_email metadata)',{status:200}); }
        const user = await env.USERS_KV.get(email.toLowerCase(),'json');
        if(!user){ return new Response('ok (user not found)',{status:200}); }

        // ===== BRANCH A: CREDIT PACK purchase (no ti_program; identified by ti_pack_size) =====
        const packSizeStr = cs.metadata?.ti_pack_size;
        if(packSizeStr){
          const packSize = parseInt(packSizeStr, 10);
          if(!(packSize >= 4 && packSize <= 12)){
            return new Response('ok (invalid pack size in metadata)', {status:200});
          }
          const csMode = cs.metadata?.ti_mode || 'one_time';
          const stripeRef = csMode === 'monthly' ? (cs.subscription || cs.id) : (cs.payment_intent || cs.id);
          // Idempotency — if /api/claim-purchase already wrote this lot, do nothing
          const existing = (user.credits||[]).find(c => c.stripeId === stripeRef);
          if(existing){
            return new Response('ok (pack already credited via claim endpoint)', {status:200});
          }
          const now = Date.now();
          const lot = {
            id: newToken(8),
            count: packSize,
            used: 0,
            purchasedAt: now,
            expiresAt: now + 30*24*60*60*1000,
            source: csMode + '_webhook_fallback',
            stripeId: stripeRef
          };
          user.credits = (user.credits||[]).concat([lot]);
          if(csMode === 'monthly'){
            user.subscription = Object.assign(user.subscription||{}, {
              active: true, stripeSubscriptionId: cs.subscription,
              packSize, lastInvoicedAt: now
            });
          }
          await env.USERS_KV.put(user.email, JSON.stringify(user));
          // Notify Coach (best-effort) — parent will see credits in their dashboard automatically
          try {
            await sendCoachAlert(env, 'session_purchase', {
              user, packSize, mode: csMode, expiresAt: lot.expiresAt
            });
          } catch(_){}
          return new Response(`ok (pack credited via webhook fallback: ${packSize} sessions)`, {status:200});
        }

        // ===== BRANCH B: PROGRAM-keyed flows (camps, monday-monthly, academy, etc.) =====
        const programKey = cs.metadata?.ti_program;
        if(!programKey){ return new Response('ok (no ti_program metadata)',{status:200}); }
        const stripeRef = cs.subscription || cs.payment_intent || cs.id;
        const already = (user.bookings||[]).find(b => b.stripeRef === stripeRef)
                     || (user.preorders||[]).find(p => p.stripeRef === stripeRef);
        if(already){ return new Response('ok (already claimed)',{status:200}); }

        const cfg = PROGRAMS_CATALOG[programKey];
        if(!cfg){ return new Response('ok (unknown program)',{status:200}); }

        // Pre-order — just record it
        if(cfg.preorder){
          user.preorders = (user.preorders||[]).concat([{
            id: newToken(8), program: programKey, slug: cfg.preorderSlug,
            stripeRef, mode: cfg.stripeMode, priceCents: cfg.priceCents,
            paidAt: Date.now(), status:'reserved'
          }]);
          await env.USERS_KV.put(user.email, JSON.stringify(user));
          return new Response('ok (preorder recorded via webhook)',{status:200});
        }
        // Defer Cal.com bookings to claim endpoint — webhook just notes payment
        return new Response('ok (defer to claim)', {status:200});
      }

      default:
        return new Response(`ok (unhandled: ${type})`, {status:200});
    }
  } catch(e){
    console.log('webhook handler error:', e?.message, e?.stack);
    return new Response('error: '+(e?.message||'unknown'), {status:500});
  }
}

// ==== camp_details_handler.js ====
// ============================================================
// CAMP DETAILS  —  collect extra fields before camp checkout
// ============================================================
async function handleSaveCampDetails(request, env){
  if(request.method !== 'POST') return new Response('Method not allowed',{status:405});
  const auth = await requireAuth(request, env);
  if(!auth) return jsonResponse({error:'Not signed in'},401);
  let body;
  try { body = await request.json(); } catch { return jsonResponse({error:'Invalid JSON'},400); }
  const camp = (body.camp||'').trim();
  if(camp !== 'camps-morning' && camp !== 'camps-afternoon') return jsonResponse({error:'Invalid camp'},400);

  // Required fields
  const required = ['playerShirt','playerPosition','playerThrows','emergencyName','emergencyPhone','emergencyRelation','waiver'];
  for(const f of required){
    if(body[f] === undefined || body[f] === null || body[f] === '') return jsonResponse({error:`Missing required field: ${f}`},400);
  }
  if(body.waiver !== true && body.waiver !== 'true' && body.waiver !== 'on') return jsonResponse({error:'Waiver acceptance required'},400);

  const user = await env.USERS_KV.get(auth.user.email, 'json');
  if(!user) return jsonResponse({error:'User not found'},404);

  // Build a CampRegistration record (one per camp, replaces any existing for same camp)
  const reg = {
    camp,
    playerShirt: String(body.playerShirt||'').trim(),
    playerPosition: String(body.playerPosition||'').trim(),
    playerThrows: String(body.playerThrows||'').trim(),
    emergencyName: String(body.emergencyName||'').trim(),
    emergencyPhone: String(body.emergencyPhone||'').trim(),
    emergencyRelation: String(body.emergencyRelation||'').trim(),
    medical: String(body.medical||'').trim(),
    pickupAuthorized: String(body.pickupAuthorized||'').trim(),
    photoRelease: body.photoRelease === true || body.photoRelease === 'true' || body.photoRelease === 'on',
    loanerGear: body.loanerGear === true || body.loanerGear === 'true' || body.loanerGear === 'on',
    notes: String(body.notes||'').trim(),
    waiverAcceptedAt: Date.now()
  };

  // Detect: is this the first time the form is being saved for this camp?
  // If yes, fire a notification email to Coach (best-effort, doesn't fail the request).
  const wasFirstRegistration = !(user.campRegistrations||[]).find(r => r.camp === camp);
  user.campRegistrations = (user.campRegistrations||[]).filter(r => r.camp !== camp).concat([reg]);
  await env.USERS_KV.put(user.email, JSON.stringify(user));
  if(wasFirstRegistration){
    try { await sendCampNotification(env, user, reg, 'form_submitted'); } catch(_){}
  }
  return jsonResponse({ ok:true });
}

async function handleGetCampDetails(request, env){
  const auth = await requireAuth(request, env);
  if(!auth) return jsonResponse({error:'Not signed in'},401);
  const url = new URL(request.url);
  const camp = url.searchParams.get('camp') || '';
  const user = await env.USERS_KV.get(auth.user.email, 'json');
  const existing = (user && user.campRegistrations || []).find(r => r.camp === camp);
  return jsonResponse({ details: existing || null });
}

async function handleAdminUserDelete(request, env, email){
  const a = await requireAdmin(request, env);
  if(a.error) return a.error;
  if(isAdminEmail(email)) return jsonResponse({error:'Cannot delete an admin account'},403);
  const user = await env.USERS_KV.get(email, 'json');
  if(!user) return jsonResponse({error:'User not found'},404);
  // Cancel all Cal.com bookings on file
  let cancelledBookings = 0; const calErrors = [];
  for(const b of (user.bookings||[])){
    if(!b.calBookingUid) continue;
    try {
      const r = await fetch('https://api.cal.com/v2/bookings/'+encodeURIComponent(b.calBookingUid)+'/cancel', {
        method:'POST',
        headers:{ 'Authorization': `Bearer ${env.CAL_COM_API_KEY}`, 'cal-api-version':'2024-08-13', 'Content-Type':'application/json' },
        body: JSON.stringify({ cancellationReason: 'User account deleted by admin' })
      });
      if(r.ok) cancelledBookings++;
      else { const t = await r.text(); calErrors.push({uid:b.calBookingUid, err:t.slice(0,80)}); }
    } catch(e){ calErrors.push({uid:b.calBookingUid, err:String(e?.message||e)}); }
  }
  // Delete user record
  await env.USERS_KV.delete(email);
  // Wipe their sessions (best effort)
  try {
    let cursor;
    do {
      const page = await env.SESSIONS_KV.list({ cursor, limit:1000 });
      for(const k of page.keys){
        const raw = await env.SESSIONS_KV.get(k.name);
        if(!raw) continue;
        try {
          const sess = JSON.parse(raw);
          if((sess.email||'').toLowerCase() === email.toLowerCase()){ await env.SESSIONS_KV.delete(k.name); }
        } catch{}
      }
      cursor = page.list_complete ? undefined : page.cursor;
    } while(cursor);
  } catch(e){ console.log('session cleanup failed:', e?.message); }
  return jsonResponse({ ok:true, deleted: email, cancelledBookings, calErrors: calErrors.length ? calErrors : undefined });
}

async function handleAdminUserDetailOrUpdate(request, env, email){
  if(request.method === "GET") return handleAdminUserDetail(request, env, email);
  if(request.method === "DELETE") return handleAdminUserDelete(request, env, email);
  return handleAdminUserUpdate(request, env, email);
}



async function handlePublicSlots(request, env){
  const url = new URL(request.url);
  const start = url.searchParams.get('start') || new Date().toISOString();
  const endParam = url.searchParams.get('end');
  const endDate = endParam ? new Date(endParam) : new Date(Date.now() + 14*24*60*60*1000);
  const endISO = endDate.toISOString();
  // Program-aware event picker
  const programSlug = url.searchParams.get('program') || 'one-on-one';
  let eventId = 6031855; // 1-on-1 default
  if(programSlug === 'monday-drop-in' || programSlug === 'monday-monthly' || programSlug === 'academy') eventId = 6031818;
  // Try multiple Cal.com endpoints (v2 first, v1 fallback)
  const tries = [
    { path:'/v2/slots/available', version:'2024-08-13', params:{ eventTypeId:String(eventId), startTime:start, endTime:endISO, timeZone:'America/Toronto' } },
    { path:'/v1/slots', version:'2024-08-13', params:{ eventTypeId:String(eventId), startTime:start, endTime:endISO, timeZone:'America/Toronto', apiKey: env.CAL_COM_API_KEY } },
    { path:'/v2/slots', version:'2024-09-04', params:{ eventTypeId:String(eventId), start:start.slice(0,10), end:endISO.slice(0,10), timeZone:'America/Toronto' } }
  ];
  let lastErr = null;
  for(const t of tries){
    const ps = new URLSearchParams(t.params);
    const headers = { 'cal-api-version':t.version, 'Content-Type':'application/json' };
    if(t.path.startsWith('/v2')){ headers['Authorization'] = `Bearer ${env.CAL_COM_API_KEY}`; }
    try {
      const r = await fetch(`https://api.cal.com${t.path}?${ps}`, { method:'GET', headers });
      const txt = await r.text();
      let body; try { body = JSON.parse(txt); } catch { body = { raw: txt }; }
      if(!r.ok){ lastErr = { path:t.path, status:r.status, body }; continue; }
      let data = body?.data?.slots || body?.data || {};
      if(Array.isArray(data)){
        const grouped = {};
        for(const s of data){
          const startStr = s.time || s.start || s.startTime;
          if(!startStr) continue;
          const day = startStr.slice(0,10);
          (grouped[day] = grouped[day] || []).push({ start: startStr, time: startStr });
        }
        data = grouped;
      }
      return jsonResponse({ slots: data });
    } catch(e){ lastErr = { path:t.path, error:String(e.message||e) }; }
  }
  return jsonResponse({error:'Cal.com slots error', detail: lastErr},502);
}




