// ============================================================

async function handleAdminCreateUser(request, env){
  const a = await requireAdmin(request, env);
  if(a.error) return a.error;
  if(request.method !== 'POST') return new Response('Method not allowed',{status:405});
  let body;
  try { body = await request.json(); } catch { return jsonResponse({error:'Invalid JSON'},400); }

  const email = (body.email||'').trim().toLowerCase();
  const parentName = (body.parentName||'').trim();
  if(!email || !/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)) return jsonResponse({error:'Valid email required'},400);
  if(!parentName) return jsonResponse({error:'Parent name required'},400);
  const existing = await env.USERS_KV.get(email);
  if(existing) return jsonResponse({error:'A user with that email already exists'},409);

  // Random temporary password — admin tells parent to use "Forgot password"
  // to set their own. We hash it the same way createUser does.
  const tempPw = newToken(16);
  const passwordHash = await hashPassword(tempPw);

  const user = {
    email,
    parentName,
    athleteName: (body.athleteName||'').trim(),
    athleteDob: (body.athleteDob||'').trim(),
    level: (body.level||'').trim(),
    phone: (body.phone||'').trim(),
    passwordHash,
    stripeCustomerId: null,
    credits: [],
    bookings: [],
    subscription: null,
    createdAt: Date.now(),
    createdBy: 'admin',
    createdByEmail: a.user?.email || 'admin'
  };
  await env.USERS_KV.put(email, JSON.stringify(user));
  return jsonResponse({ ok:true, email, parentName, athleteName: user.athleteName });
}

async function handleAdminToggleCampPaid(request, env, email){
  const a = await requireAdmin(request, env);
  if(a.error) return a.error;
  if(request.method !== 'POST') return new Response('Method not allowed',{status:405});
  let body;
  try { body = await request.json(); } catch { return jsonResponse({error:'Invalid JSON'},400); }
  const camp = (body.camp||'').trim();
  const wantPaid = body.paid === true || body.paid === 'true';
  if(camp !== 'camps-morning' && camp !== 'camps-afternoon') return jsonResponse({error:'Invalid camp'},400);
  const user = await env.USERS_KV.get(email.toLowerCase(), 'json');
  if(!user) return jsonResponse({error:'User not found'},404);

  user.bookings = user.bookings || [];
  const existingIdx = user.bookings.findIndex(b => b.source === camp && b.stripeRef);
  if(wantPaid){
    if(existingIdx === -1){
      user.bookings.push({
        calBookingUid: null,
        startTime: null,
        bookedAt: Date.now(),
        status: 'paid',
        stripeRef: 'admin_manual_' + Date.now(),
        source: camp,
        markedPaidBy: a.user?.email || 'admin'
      });
    }
    await env.USERS_KV.put(user.email, JSON.stringify(user));
    return jsonResponse({ ok:true, paid:true });
  } else {
    // Only remove an admin-marked one; never delete a real Stripe payment
    if(existingIdx !== -1 && String(user.bookings[existingIdx].stripeRef||'').startsWith('admin_manual_')){
      user.bookings.splice(existingIdx, 1);
      await env.USERS_KV.put(user.email, JSON.stringify(user));
      return jsonResponse({ ok:true, paid:false });
    }
    if(existingIdx !== -1){
      return jsonResponse({error:'Cannot unmark — this camp was paid via a real Stripe payment (ref ' + String(user.bookings[existingIdx].stripeRef||'').slice(0,20) + '). Refund in Stripe instead.'},400);
    }
    return jsonResponse({ ok:true, paid:false, note:'already unpaid' });
  }
}

async function handleAdminEnrollCamp(request, env, email){
  const a = await requireAdmin(request, env);
  if(a.error) return a.error;
  if(request.method !== 'POST') return new Response('Method not allowed',{status:405});
  let body;
  try { body = await request.json(); } catch { return jsonResponse({error:'Invalid JSON'},400); }
  const camp = (body.camp||'').trim();
  if(camp !== 'camps-morning' && camp !== 'camps-afternoon') return jsonResponse({error:'Invalid camp'},400);
  const user = await env.USERS_KV.get(email.toLowerCase(), 'json');
  if(!user) return jsonResponse({error:'User not found'},404);

  const reg = {
    camp,
    playerShirt: String(body.playerShirt||'').trim(),
    playerPosition: String(body.playerPosition||'').trim(),
    playerThrows: String(body.playerThrows||'').trim(),
    emergencyName: String(body.emergencyName||'').trim(),
    emergencyPhone: String(body.emergencyPhone||'').trim(),
    emergencyRelation: String(body.emergencyRelation||'').trim(),
    medical: String(body.medical||'').trim(),
    pickupAuthorized: String(body.pickupAuthorized||'').trim(),
    photoRelease: body.photoRelease === true || body.photoRelease === 'true' || body.photoRelease === 'on',
    loanerGear: body.loanerGear === true || body.loanerGear === 'true' || body.loanerGear === 'on',
    notes: String(body.notes||'').trim(),
    waiverAcceptedAt: Date.now(),
    enrolledByAdmin: a.user?.email || 'admin'
  };
  user.campRegistrations = (user.campRegistrations||[]).filter(r => r.camp !== camp).concat([reg]);
  // Optionally mark paid
  if(body.paid === true || body.paid === 'true'){
    user.bookings = user.bookings || [];
    if(!user.bookings.find(b => b.source === camp && b.stripeRef)){
      user.bookings.push({
        calBookingUid: null, startTime: null, bookedAt: Date.now(),
        status: 'paid', stripeRef: 'admin_manual_' + Date.now(),
        source: camp, markedPaidBy: a.user?.email || 'admin'
      });
    }
  }
  await env.USERS_KV.put(user.email, JSON.stringify(user));
  return jsonResponse({ ok:true });
}

async function handleAdminBookMondayNight(request, env, email){
  const a = await requireAdmin(request, env);
  if(a.error) return a.error;
  if(request.method !== 'POST') return new Response('Method not allowed',{status:405});
  let body;
  try { body = await request.json(); } catch { return jsonResponse({error:'Invalid JSON'},400); }
  const slotIso = (body.slot || '').trim();
  const monthly = body.monthly === true || body.monthly === 'true';
  const paid = body.paid === true || body.paid === 'true';
  if(!slotIso || !/^\d{4}-\d{2}-\d{2}T/.test(slotIso)) return jsonResponse({error:'Invalid slot start time'},400);
  const user = await env.USERS_KV.get(email.toLowerCase(), 'json');
  if(!user) return jsonResponse({error:'User not found'},404);

  const cfg = PROGRAMS_CATALOG['monday-drop-in'];
  const stripeRef = 'admin_manual_' + Date.now();

  // Create Cal.com booking for this slot
  const res = await createCalBookingForUser(env, user, cfg.calEventId, slotIso, {
    ti_program: monthly ? 'monday-monthly' : 'monday-drop-in',
    ti_stripe_ref: stripeRef,
    ti_admin_booked: 'true'
  });
  if(!res.ok){
    return jsonResponse({ ok:false, calError: res.error || 'Could not create Cal.com booking' }, 502);
  }

  user.bookings = (user.bookings||[]).concat([{
    calBookingUid: res.uid,
    startTime: slotIso,
    bookedAt: Date.now(),
    status: paid ? 'paid' : 'accepted',
    stripeRef: paid ? stripeRef : null,
    source: monthly ? 'monday-monthly' : 'monday-drop-in',
    bookedByAdmin: a.user?.email || 'admin'
  }]);
  await env.USERS_KV.put(user.email, JSON.stringify(user));
  return jsonResponse({ ok:true, bookingUid: res.uid, slotStart: slotIso });
}



async function handleAdminBookOneOnOne(request, env, email){
  const a = await requireAdmin(request, env);
  if(a.error) return a.error;
  if(request.method !== 'POST') return new Response('Method not allowed',{status:405});
  let body;
  try { body = await request.json(); } catch { return jsonResponse({error:'Invalid JSON'},400); }
  const slotIso = (body.slot || '').trim();
  // payment: 'credit' | 'paid' | 'untracked'
  const payment = String(body.payment || 'untracked').toLowerCase();
  if(!slotIso || !/^\d{4}-\d{2}-\d{2}T/.test(slotIso)) return jsonResponse({error:'Invalid slot start time'},400);
  const user = await env.USERS_KV.get(email.toLowerCase(), 'json');
  if(!user) return jsonResponse({error:'User not found'},404);

  // 1-on-1 Cal.com event id (matches CAL_ONE_ON_ONE_EVENT_ID = 6031855 used in booking handler)
  const ONE_ON_ONE_EVENT = 6031855;

  // If using a credit, find an earliest-expiring active lot first (don't book if none available)
  let lotToDecrement = null;
  if(payment === 'credit'){
    const now = Date.now();
    for(const lot of (user.credits||[])){
      const rem = (lot.count||0) - (lot.used||0);
      if(rem <= 0) continue;
      if(lot.expiresAt <= now) continue;
      if(!lotToDecrement || lot.expiresAt < lotToDecrement.expiresAt) lotToDecrement = lot;
    }
    if(!lotToDecrement) return jsonResponse({error:'No active credits available for this user — use "Mark Paid" or "No payment tracking" instead, or grant credits first.'},402);
  }

  const stripeRef = payment === 'paid' ? ('admin_manual_' + Date.now()) : null;

  // Create Cal.com booking
  const res = await createCalBookingForUser(env, user, ONE_ON_ONE_EVENT, slotIso, {
    ti_program: 'one-on-one',
    ti_admin_booked: 'true',
    ti_payment_mode: payment,
    ...(stripeRef ? { ti_stripe_ref: stripeRef } : {})
  });
  if(!res.ok){
    return jsonResponse({ ok:false, calError: res.error || 'Could not create Cal.com booking' }, 502);
  }

  // Decrement credit if using one
  if(lotToDecrement){
    const idx = user.credits.findIndex(l => l.id === lotToDecrement.id);
    if(idx >= 0) user.credits[idx].used = (user.credits[idx].used||0) + 1;
  }

  user.bookings = (user.bookings||[]).concat([{
    calBookingUid: res.uid,
    startTime: slotIso,
    bookedAt: Date.now(),
    status: payment === 'paid' ? 'paid' : 'accepted',
    stripeRef,
    creditLotId: lotToDecrement ? lotToDecrement.id : null,
    source: payment === 'credit' ? '1-on-1 (credit)' : (payment === 'paid' ? '1-on-1 (admin paid)' : '1-on-1 (admin booked)'),
    bookedByAdmin: a.user?.email || 'admin'
  }]);
  await env.USERS_KV.put(user.email, JSON.stringify(user));
  return jsonResponse({ ok:true, bookingUid: res.uid, slotStart: slotIso,
                        creditUsed: !!lotToDecrement, paidMarked: payment === 'paid' });
}

export default {
  async fetch(request, env, ctx){
    const url = new URL(request.url);
    const p = url.pathname;

    // Static assets (inlined)
    if(p==='/assets/logo.png') return new Response(b64ToBytes(LOGO_PNG_B64),{headers:{'Content-Type':'image/png','Cache-Control':'public, max-age=86400'}});
    if(p==='/assets/camp-action-hero.jpg') return new Response(b64ToBytes(CAMP_ACTION_HERO_B64),{headers:{'Content-Type':'image/jpeg','Cache-Control':'public, max-age=86400'}});
    if(p==='/assets/camp-tee-player.jpg') return new Response(b64ToBytes(CAMP_TEE_PLAYER_B64),{headers:{'Content-Type':'image/jpeg','Cache-Control':'public, max-age=86400'}});
    if(p==='/script.js') return new Response(SCRIPT_JS,{headers:{'Content-Type':'application/javascript; charset=utf-8','Cache-Control':'public, max-age=0, must-revalidate'}});

    // Pages
    if(p==='/'||p==='/index.html') return html(INDEX_HTML);
    if(p==='/coach'||p==='/coach.html') return html(COACH_HTML);
    if(p==='/programs'||p==='/programs.html') return html(PROGRAMS_HTML);
    if(p==='/camps'||p==='/camps.html') return html(CAMPS_HTML);
    if(p==='/beginners'||p==='/beginners.html') return html(BEGINNERS_HTML);
    if(p==='/camps/register'||p==='/camps/register.html'||p==='/camps-register'||p==='/camps-register.html') return Response.redirect(new URL('/camps', request.url), 301);
    if(p==='/academy'||p==='/academy.html') return html(ACADEMY_HTML);
    if(p==='/contact'||p==='/contact.html') return html(CONTACT_HTML);
    if(p==='/manage'||p==='/manage.html') return html(MANAGE_HTML);
    if(p==='/waiver'||p==='/waiver.html') return html(WAIVER_HTML);
    if(p==='/schedule'||p==='/schedule.html') return html(SCHEDULE_HTML);
    if(p==='/facility'||p==='/facility.html') return html(FACILITY_HTML);
    if(p==='/pricing'||p==='/pricing.html') return Response.redirect(new URL('/programs', request.url),301);

    // Auth pages
    if(p==='/login'||p==='/login.html') return html(LOGIN_HTML);
    if(p==='/signup'||p==='/signup.html') return html(SIGNUP_HTML);
    if(p==='/dashboard'||p==='/dashboard.html') return html(DASHBOARD_HTML);
    if(p==='/forgot-password'||p==='/forgot-password.html') return html(FORGOT_HTML);
    if(p==='/reset-password'||p==='/reset-password.html') return html(RESET_HTML);
    if(p==='/dashboard/buy'||p==='/dashboard/buy.html') return html(BUY_HTML);
    if(p==='/dashboard/book'||p==='/dashboard/book.html') return html(BOOK_HTML);
    // /book redirects for legacy tryout-prep slugs
    if(p==='/book' && url.searchParams.get('program')==='tryout-prep-monthly'){ return Response.redirect(new URL('/book?program=academy-monthly', request.url),301); }
    if(p==='/book' && url.searchParams.get('program')==='tryout-prep-season'){ return Response.redirect(new URL('/book?program=academy-full', request.url),301); }
    if(p==='/book'||p==='/book.html') return html(QUICKBOOK_HTML);
    if(p==='/admin'||p==='/admin.html'||p==='/admin/') return html(ADMIN_HTML);

    // Auth API
    if(p==='/api/auth/signup') return handleSignup(request,env);
    if(p==='/api/auth/login') return handleLogin(request,env);
    if(p==='/api/auth/logout') return handleLogout(request,env);
    if(p==='/api/auth/forgot-password') return handleForgotPassword(request,env);
    if(p==='/api/auth/reset-password') return handleResetPassword(request,env);
    if(p==='/api/me') return handleMe(request,env);

    // Booking/buy
    if(p==='/api/checkout') return handleCheckout(request,env);
    if(p==='/api/claim-purchase') return handleClaimPurchase(request,env);
    if(p==='/api/available-slots') return handleAvailableSlots(request,env);
    if(p==='/api/book-session') return handleBookSession(request,env);
    if(p==='/api/my-bookings') return handleMyBookings(request,env);
    if(p==='/api/public-slots') return handlePublicSlots(request,env);
    if(p==='/api/program-config') return handleProgramConfig(request,env);
    if(p==='/api/program-spots') return handleProgramSpots(request,env);
    if(p==='/api/program-checkout') return handleProgramCheckout(request,env);
    if(p==='/api/claim-program-booking') return handleClaimProgramBooking(request,env);
    if(p==='/api/single-checkout') return handleSingleCheckout(request,env);
    if(p==='/api/claim-single-booking') return handleClaimSingleBooking(request,env);

    // Camp registration extras
    if(p==='/api/save-camp-details') return handleSaveCampDetails(request,env);
    if(p==='/api/get-camp-details') return handleGetCampDetails(request,env);

    // Beginners program
    if(p==='/api/beginners-reserve') return handleBeginnersReserve(request,env);
    if(p==='/api/admin/beginners-leads') return handleAdminBeginnersLeads(request,env);
    {
      const mB = p.match(/^\/api\/admin\/beginners-leads\/([^\/]+)$/);
      if(mB) return handleAdminBeginnersLeadUpdate(request,env,decodeURIComponent(mB[1]));
    }

    // Stripe webhook
    if(p==='/api/stripe-webhook') return handleStripeWebhook(request,env);

    // Admin API
    if(p==='/api/admin/users') return handleAdminUsers(request,env);
    if(p==='/api/admin/calendar') return handleAdminCalendar(request,env);
    // Admin productivity endpoints
    if(p==='/api/admin/create-user') return handleAdminCreateUser(request, env);
    {
      const mP = p.match(/^\/api\/admin\/users\/([^\/]+)\/camp-paid$/);
      if(mP) return handleAdminToggleCampPaid(request, env, decodeURIComponent(mP[1]));
      const mE = p.match(/^\/api\/admin\/users\/([^\/]+)\/enroll-camp$/);
      if(mE) return handleAdminEnrollCamp(request, env, decodeURIComponent(mE[1]));
      const mM = p.match(/^\/api\/admin\/users\/([^\/]+)\/book-monday$/);
      if(mM) return handleAdminBookMondayNight(request, env, decodeURIComponent(mM[1]));
      const mO = p.match(/^\/api\/admin\/users\/([^\/]+)\/book-one-on-one$/);
      if(mO) return handleAdminBookOneOnOne(request, env, decodeURIComponent(mO[1]));
    }
    {
      const mRec = p.match(/^\/api\/admin\/reconcile-user\/([^\/]+)$/);
      if(mRec) return handleAdminReconcileUser(request, env, decodeURIComponent(mRec[1]));
    }
    {
      const m1 = p.match(/^\/api\/admin\/users\/([^\/]+)$/);
      if(m1) return handleAdminUserDetailOrUpdate(request,env,decodeURIComponent(m1[1]));
      const m2 = p.match(/^\/api\/admin\/users\/([^\/]+)\/credits$/);
      if(m2) return handleAdminAddCredits(request,env,decodeURIComponent(m2[1]));
      const m3 = p.match(/^\/api\/admin\/users\/([^\/]+)\/credits\/([^\/]+)$/);
      if(m3) return handleAdminLotAction(request,env,decodeURIComponent(m3[1]),decodeURIComponent(m3[2]));
    }

    return env.ASSETS.fetch(request);
  }
};
